####################
##  health_assessment
####################
DROP TABLE IF EXISTS `health_assessment`;

####################
##  table health_assessment ddl
####################
CREATE TABLE `health_assessment` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `elder_name` varchar(255) DEFAULT NULL COMMENT '老人姓名',
  `id_card` varchar(255) DEFAULT NULL COMMENT '身份证号',
  `birth_date` datetime DEFAULT NULL COMMENT '出生日期',
  `age` int DEFAULT NULL COMMENT '年龄',
  `gender` int DEFAULT NULL COMMENT '性别(0:男，1:女)',
  `health_score` varchar(255) DEFAULT NULL COMMENT '健康评分',
  `risk_level` varchar(255) DEFAULT NULL COMMENT '严重危险(健康, 提示, 风险, 危险, 严重危险)',
  `suggestion_for_admission` int DEFAULT NULL COMMENT '是否建议入住(0:建议，1:不建议)',
  `nursing_level_name` varchar(255) DEFAULT NULL COMMENT '推荐护理等级',
  `admission_status` int DEFAULT NULL COMMENT '入住情况(0:已入住，1:未入住)',
  `total_check_date` varchar(64) DEFAULT NULL COMMENT '总检日期',
  `physical_exam_institution` varchar(255) DEFAULT NULL COMMENT '体检机构',
  `physical_report_url` varchar(255) DEFAULT NULL COMMENT '体检报告URL链接',
  `assessment_time` datetime DEFAULT NULL COMMENT '评估时间',
  `report_summary` text COMMENT '报告总结',
  `disease_risk` text COMMENT '疾病风险',
  `abnormal_analysis` text COMMENT '异常分析',
  `system_score` varchar(255) DEFAULT NULL COMMENT '健康系统分值',
  `create_by` varchar(255) DEFAULT NULL COMMENT '创建者',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(255) DEFAULT NULL COMMENT '更新者',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `remark` text COMMENT '备注',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='健康评估表';

####################
##  health_assessment data
####################

####################
##  health_assessment data
####################
INSERT INTO `health_assessment`(`system_score`,`nursing_level_name`,`gender`,`total_check_date`,`create_time`,`disease_risk`,`birth_date`,`health_score`,`id_card`,`abnormal_analysis`,`physical_exam_institution`,`create_by`,`risk_level`,`assessment_time`,`suggestion_for_admission`,`admission_status`,`physical_report_url`,`elder_name`,`id`,`age`,`report_summary`) VALUES ('{`breathingSystem`:95,`digestiveSystem`:85,`endocrineSystem`:90,`immuneSystem`:95,`circulatorySystem`:80,`urinarySystem`:85,`motionSystem`:95,`senseSystem`:80}','一级护理等级',0,'2023-10-10','2024-09-16T00:09:31','{`healthy`:60,`caution`:30,`risk`:10,`danger`:0,`severeDanger`:0}','1967-12-13T00:00','80.25','132112196712137788','[{`conclusion`:`心率偏快`,`examinationItem`:`心率`,`result`:`92`,`referenceValue`:`<90`,`unit`:`次/分`,`interpret`:`心率稍高于正常范围，可能与紧张、活动或轻度心律失常有关。`,`advice`:`建议定期进行心电图检查，保持心情平静，避免过度劳累。`},{`conclusion`:`视力下降`,`examinationItem`:`视力`,`result`:`左眼0.3，右眼0.4`,`referenceValue`:`≥1.0`,`unit`:`-`,`interpret`:`视力明显低于正常范围，符合老视特征。`,`advice`:`建议配戴合适的老花镜，避免长时间用眼，定期检查视力。`},{`conclusion`:`轻度脂肪肝可能`,`examinationItem`:`肝脏B超`,`result`:`实质回声略粗糙`,`referenceValue`:`-`,`unit`:`-`,`interpret`:`肝脏实质回声略粗糙可能提示轻度脂肪肝，与脂肪代谢异常有关。`,`advice`:`建议低脂饮食，适量运动，控制体重，避免饮酒，定期检查肝脏情况。`},{`conclusion`:`慢性胆囊炎可能`,`examinationItem`:`胆囊B超`,`result`:`胆囊壁毛糙`,`referenceValue`:`-`,`unit`:`-`,`interpret`:`胆囊壁毛糙可能提示慢性胆囊炎，与胆囊炎症或结石刺激有关。`,`advice`:`建议保持饮食规律，避免高脂食物，定期检查胆囊情况，如有症状及时就医。`},{`conclusion`:`脾轻度增大`,`examinationItem`:`脾脏B超`,`result`:`脾轻度增大`,`referenceValue`:`-`,`unit`:`-`,`interpret`:`脾脏轻度增大可能与感染、炎症或其他疾病有关。`,`advice`:`建议进一步检查脾脏增大的原因，定期监测脾脏情况。`},{`conclusion`:`右肾小囊肿可能`,`examinationItem`:`肾脏B超`,`result`:`右肾下极见一大小约5mm的无回声区`,`referenceValue`:`-`,`unit`:`mm`,`interpret`:`右肾小囊肿可能与肾小管憩室增多有关，一般无需特殊处理。`,`advice`:`建议定期检查肾脏B超，观察囊肿变化，如有症状及时就医。`},{`conclusion`:`前列腺形态略增大`,`examinationItem`:`前列腺B超`,`result`:`形态略增大`,`referenceValue`:`-`,`unit`:`-`,`interpret`:`前列腺形态略增大可能与前列腺增生有关，是老年男性常见疾病。`,`advice`:`建议进行PSA检查以排除前列腺肿瘤，定期检查前列腺情况。`}]','黑马体检','1','caution','2024-09-16T00:09:31',0,0,'https://itheim.oss-cn-beijing.aliyuncs.com/43267d42-9a21-4e71-bf5d-2e938cef85d3.pdf','刘爱国',8,56,'体检报告中心率、视力、肝脏B超、胆囊B超、脾脏B超、肾脏B超、前列腺B超共7项指标提示异常。综合这些临床指标和数据分析：循环系统、消化系统、泌尿系统存在隐患，其中循环系统、消化系统有“中危”风险；泌尿系统有“低危”风险。建议定期进行相关检查，保持健康的生活方式。');
INSERT INTO `health_assessment`(`system_score`,`nursing_level_name`,`gender`,`total_check_date`,`create_time`,`disease_risk`,`birth_date`,`health_score`,`id_card`,`abnormal_analysis`,`physical_exam_institution`,`create_by`,`risk_level`,`assessment_time`,`suggestion_for_admission`,`admission_status`,`physical_report_url`,`elder_name`,`id`,`age`,`report_summary`) VALUES ('{`breathingSystem`:90,`digestiveSystem`:85,`endocrineSystem`:80,`immuneSystem`:80,`circulatorySystem`:75,`urinarySystem`:75,`motionSystem`:90,`senseSystem`:85}','一级护理等级',1,'2023.10.10','2024-09-16T16:05:31','{`healthy`:60,`caution`:30,`risk`:10,`danger`:0,`severeDanger`:0}','1952-08-12T00:00','75.0','132123195208121235','[{`conclusion`:`双下肢轻微凹陷性水肿`,`examinationItem`:`内科`,`result`:`双下肢轻微凹陷性水肿`,`referenceValue`:`-`,`unit`:`-`,`interpret`:`可能由心肾功能异常引起，需进一步检查以确定具体原因。`,`advice`:`建议进一步检查心肾功能，根据检查结果采取相应治疗措施。平时避免长时间站立，可抬高下肢休息，以减轻水肿。`},{`conclusion`:`视力略有下降`,`examinationItem`:`眼科`,`result`:`视力左0.5/，视力右0.6/`,`referenceValue`:`-`,`unit`:`-`,`interpret`:`视力下降是老化的常见表现，可能与眼部疾病或不良用眼习惯有关。`,`advice`:`建议定期复查视力，考虑配戴合适的老花镜。平时注意用眼卫生，避免长时间用眼。`},{`conclusion`:`右耳听力下降`,`examinationItem`:`耳鼻喉科`,`result`:`右耳听力下降`,`referenceValue`:`-`,`unit`:`-`,`interpret`:`听力下降可能与年龄、耳部疾病或长期暴露于噪音环境有关。`,`advice`:`建议耳鼻喉科进一步评估，找出听力下降的具体原因。平时避免长时间暴露于噪音环境，注意保护听力。`},{`conclusion`:`血压偏高`,`examinationItem`:`一般科室`,`result`:`收缩压145mmHg，舒张压90mmHg`,`referenceValue`:`收缩压<140mmHg，舒张压<90mmHg`,`unit`:`mmHg`,`interpret`:`血压偏高可能增加心脑血管疾病的风险。`,`advice`:`建议定期监测血压，改善生活方式（如低盐饮食、适量运动、戒烟限酒等）。必要时心内科随访，考虑药物治疗。`},{`conclusion`:`血红蛋白略低`,`examinationItem`:`血常规`,`result`:`血红蛋白110g/l`,`referenceValue`:`120-160g/l`,`unit`:`g/l`,`interpret`:`血红蛋白略低可能提示轻度贫血，需关注营养状况。`,`advice`:`建议增加富含铁质的食物摄入，如瘦肉、动物肝脏、绿叶蔬菜等。必要时咨询医生，考虑补充铁剂。`},{`conclusion`:`尿蛋白微量`,`examinationItem`:`尿常规`,`result`:`尿蛋白微量`,`referenceValue`:`-`,`unit`:`-`,`interpret`:`尿蛋白微量可能提示肾功能轻度受损或泌尿系统感染。`,`advice`:`建议复查尿常规，关注肾功能。平时保持充足的水分摄入，避免过度劳累。`},{`conclusion`:`胆固醇及低密度脂蛋白略高`,`examinationItem`:`生化`,`result`:`总胆固醇6.2mmol/L，低密度脂蛋白4.0mmol/L`,`referenceValue`:`总胆固醇2.3-5.7mmol/L，低密度脂蛋白2.1-3.1mmol/L`,`unit`:`mmol/L`,`interpret`:`胆固醇及低密度脂蛋白略高可能增加动脉粥样硬化的风险。`,`advice`:`建议饮食控制，减少高脂肪、高胆固醇食物的摄入。适量增加运动，保持健康的生活方式。`},{`conclusion`:`乙肝表面抗体阴性`,`examinationItem`:`免疫`,`result`:`乙肝表面抗体阴性`,`referenceValue`:`阴性/阳性`,`unit`:`-`,`interpret`:`乙肝表面抗体阴性表示体内无乙肝抗体，对乙肝病毒无免疫力。`,`advice`:`建议接种乙肝疫苗，以增强对乙肝病毒的抵抗力。`},{`conclusion`:`脾轻度增大`,`examinationItem`:`B超`,`result`:`脾轻度增大`,`referenceValue`:`-`,`unit`:`-`,`interpret`:`脾轻度增大可能与感染、血液系统疾病或自身免疫性疾病有关。`,`advice`:`建议进一步检查以确定脾增大的具体原因。平时注意观察身体状况，如有异常及时就医。`},{`conclusion`:`右肾小囊肿可能`,`examinationItem`:`B超`,`result`:`右肾下极见一大小约5mm的无回声区，考虑小囊肿可能`,`referenceValue`:`-`,`unit`:`-`,`interpret`:`肾囊肿是一种常见的肾脏良性病变，一般无需特殊处理，但需定期复查。`,`advice`:`建议定期复查B超，关注囊肿变化。平时避免剧烈运动，以免囊肿破裂。`}]','黑马体检','1','caution','2024-09-16T16:05:31',0,1,'https://itheim.oss-cn-beijing.aliyuncs.com/fa03a618-76b7-4db5-b7b8-7fcdded51f6e.pdf','张芳',9,72,'体检报告中双下肢水肿、视力、听力、血压、血红蛋白、尿蛋白、胆固醇、低密度脂蛋白、乙肝表面抗体、脾脏、肾脏共11项指标提示异常，综合这些临床指标和数据分析：心肾功能、感官系统、循环系统、免疫系统、内分泌系统、消化系统存在隐患，其中循环系统、泌尿系统有“中危”风险；其余系统有“低危”风险。');
INSERT INTO `health_assessment`(`system_score`,`nursing_level_name`,`gender`,`total_check_date`,`create_time`,`disease_risk`,`birth_date`,`health_score`,`id_card`,`abnormal_analysis`,`physical_exam_institution`,`create_by`,`risk_level`,`assessment_time`,`suggestion_for_admission`,`admission_status`,`physical_report_url`,`elder_name`,`id`,`age`,`report_summary`) VALUES ('{`breathingSystem`:90,`digestiveSystem`:85,`endocrineSystem`:75,`immuneSystem`:80,`circulatorySystem`:65,`urinarySystem`:70,`motionSystem`:85,`senseSystem`:90}','三级护理等级',1,'2023-09-15','2024-09-16T17:25:48','{`healthy`:55,`caution`:20,`risk`:20,`danger`:5,`severeDanger`:0}','1967-12-16T00:00','68.25','132111196712161234','[{`conclusion`:`肥胖`,`examinationItem`:`体重指数BMI`,`result`:`29.2`,`referenceValue`:`>24`,`unit`:`-`,`interpret`:`体重超标包括超重与肥胖。BMI≥24为超重，BMI≥28为肥胖，体重超标是⼀种由多因素引起的慢性代谢性疾病。`,`advice`:`采取综合措施预防和控制体重，积极改变生活方式，低脂、低糖、高纤维素膳食，多食果蔬，增加有氧运动。`},{`conclusion`:`空腹血糖受损`,`examinationItem`:`空腹血糖`,`result`:`6.37`,`referenceValue`:`3.9-6.1`,`unit`:`mmol/L`,`interpret`:`空腹血糖受损是从正常过渡到糖尿病的一个过渡阶段，可能会发展为糖尿病。`,`advice`:`调整饮食，减少高糖食物摄入，适量运动，定期监测血糖，必要时就医治疗。`},{`conclusion`:`血脂异常`,`examinationItem`:`[\\`总胆固醇\\`,\\`甘油三酯\\`,\\`低密度脂蛋白胆固醇\\`]`,`result`:`[\\`5.74\\`,\\`2.17\\`,\\`3.37\\`]`,`referenceValue`:`[\\`<5.2\\`,\\`<1.7\\`,\\`<3.12\\`]`,`unit`:`mmol/L`,`interpret`:`血脂异常可能导致动脉粥样硬化，增加心脑血管病风险。`,`advice`:`低脂饮食，增加膳食纤维摄入，适量运动，必要时服用降脂药物。`},{`conclusion`:`尿蛋白弱阳性`,`examinationItem`:`尿蛋白`,`result`:`+-`,`referenceValue`:`-`,`unit`:`-`,`interpret`:`尿蛋白弱阳性可能提示肾脏功能轻度受损或生理性蛋白尿。`,`advice`:`注意休息，避免过度劳累，定期复查尿常规，如有异常及时就医。`}]','dsf  ','1','risk','2024-09-16T17:25:47',0,0,'https://itheim.oss-cn-beijing.aliyuncs.com/c6645922-30de-441f-99d6-360c731a85d3.pdf','2232',10,56,'体检报告中尿蛋白、空腹血糖、总胆固醇、甘油三酯、低密度脂蛋白胆固醇共5项指标提示异常，综合这些临床指标和数据分析：肾脏、心脑血管存在隐患，其中心脑血管有“中危”风险；肾脏部位有“低危”风险。');
INSERT INTO `health_assessment`(`system_score`,`nursing_level_name`,`gender`,`total_check_date`,`create_time`,`disease_risk`,`birth_date`,`health_score`,`id_card`,`abnormal_analysis`,`physical_exam_institution`,`create_by`,`risk_level`,`assessment_time`,`suggestion_for_admission`,`admission_status`,`physical_report_url`,`elder_name`,`id`,`age`,`report_summary`) VALUES ('{`breathingSystem`:95,`digestiveSystem`:90,`endocrineSystem`:90,`immuneSystem`:85,`circulatorySystem`:80,`urinarySystem`:85,`motionSystem`:95,`senseSystem`:90}','二级护理等级',0,'2024.09.10','2024-09-20T00:50:26','{`healthy`:60,`caution`:30,`risk`:10,`danger`:0,`severeDanger`:0}','1976-12-19T00:00','85.0','121231197612190987','[{`conclusion`:`双下肢轻微凹陷性水肿`,`examinationItem`:`内科检查`,`result`:`双下肢轻微凹陷性水肿`,`referenceValue`:`-`,`unit`:`-`,`interpret`:`双下肢凹陷性水肿可能提示心功能不全、肾功能不全或下肢静脉回流不畅等问题。`,`advice`:`建议进一步检查心肾功能，避免长时间站立或久坐，可适时抬高下肢促进血液回流。`},{`conclusion`:`右耳听力下降`,`examinationItem`:`耳鼻喉科检查`,`result`:`右耳听力下降`,`referenceValue`:`-`,`unit`:`-`,`interpret`:`听力下降可能与年龄、耳部疾病、噪音暴露或其他因素有关。`,`advice`:`建议耳鼻喉科进一步评估，并避免长时间暴露于高噪音环境中。`},{`conclusion`:`血压偏高`,`examinationItem`:`一般科室检查`,`result`:`收缩压 145 mmHg，舒张压 90 mmHg`,`referenceValue`:`收缩压<140 mmHg，舒张压<90 mmHg`,`unit`:`mmHg`,`interpret`:`血压偏高可能增加心脑血管疾病的风险。`,`advice`:`定期监测血压，调整饮食习惯，减少盐分摄入，适量运动，必要时心内科随访。`},{`conclusion`:`血红蛋白略低`,`examinationItem`:`血常规检查`,`result`:`血红蛋白 110 g/l`,`referenceValue`:`120-160 g/l`,`unit`:`g/l`,`interpret`:`血红蛋白略低可能提示轻度贫血。`,`advice`:`建议增加富含铁质的食物摄入，如瘦肉、动物肝脏等，并定期复查血常规。`},{`conclusion`:`尿蛋白微量`,`examinationItem`:`尿常规检查`,`result`:`尿蛋白（PRO）微量`,`referenceValue`:`-`,`unit`:`-`,`interpret`:`尿蛋白微量可能提示肾功能轻度受损或存在其他肾脏问题。`,`advice`:`建议复查尿常规，并关注肾功能。`},{`conclusion`:`胆固醇及低密度脂蛋白略高`,`examinationItem`:`生化检查`,`result`:`总胆固醇 6.2 mmol/L，低密度脂蛋白 4.0 mmol/L`,`referenceValue`:`总胆固醇 2.3-5.7 mmol/L，低密度脂蛋白 2.1-3.1 mmol/L`,`unit`:`mmol/L`,`interpret`:`胆固醇及低密度脂蛋白偏高可能增加心血管疾病的风险。`,`advice`:`建议饮食控制，减少高脂肪食物的摄入，适量运动，并定期复查血脂。`},{`conclusion`:`乙肝表面抗体阴性`,`examinationItem`:`免疫检查`,`result`:`乙肝表面抗体阴性`,`referenceValue`:`-`,`unit`:`-`,`interpret`:`乙肝表面抗体阴性表示体内没有产生对乙肝病毒的免疫力。`,`advice`:`建议接种乙肝疫苗以预防乙肝病毒感染。`},{`conclusion`:`脾轻度增大`,`examinationItem`:`B超检查`,`result`:`脾轻度增大`,`referenceValue`:`-`,`unit`:`-`,`interpret`:`脾轻度增大可能与多种原因有关，如感染、血液系统疾病等。`,`advice`:`建议进一步检查以确定原因，并定期监测脾脏大小。`},{`conclusion`:`右肾小囊肿可能`,`examinationItem`:`B超检查`,`result`:`右肾下极见一大小约5mm的无回声区`,`referenceValue`:`-`,`unit`:`-`,`interpret`:`右肾小囊肿可能是一种良性病变，但也需要关注其发展情况。`,`advice`:`建议定期检查肾脏B超，观察囊肿变化，如有必要可咨询专业医生进行进一步治疗。`}]','黑马','1','caution','2024-09-20T00:50:26',0,1,'https://itheim.oss-cn-beijing.aliyuncs.com/1170d925-a2ff-4435-bf9b-e12715bfa3ee.pdf','李爱国',11,47,'体检报告中尿蛋白、血压、血红蛋白、胆固醇、低密度脂蛋白、右耳听力、双下肢水肿、乙肝表面抗体、脾脏和肾脏B超共10项指标提示异常，其余指标均处于正常范围内。综合这些临床指标和数据分析：循环系统、泌尿系统存在隐患，其中循环系统有“中危”风险；泌尿系统部位有“低危”风险。');

####################
##  nursing_elder
####################
DROP TABLE IF EXISTS `nursing_elder`;

####################
##  table nursing_elder ddl
####################
CREATE TABLE `nursing_elder` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'id',
  `nursing_id` bigint DEFAULT NULL COMMENT '护理员id',
  `elder_id` bigint DEFAULT NULL COMMENT '老人id',
  `create_time` datetime NOT NULL COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `create_by` bigint DEFAULT NULL COMMENT '创建人id',
  `update_by` bigint DEFAULT NULL COMMENT '更新人id',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `nursing_id` (`nursing_id`,`elder_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=42 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='护理员老人关联表';

